mapper.insert:
/* com.educare.edu.comn.mapper.LectureDormiStdntMapper.insertByPk */
	insert into t_lecture_dormi_stdnt (
		dormi_seq	,user_id	,edu_seq		,start_dt		, end_dt
		,upd_id		,upd_de
	) values (
		#{dormiSeq}	,#{userId}	,#{eduSeq}		,#{startDt}		,#{endDt}
		,#{updId}	,#{updDe}
	)

mapper.delete:
/* com.educare.edu.comn.mapper.LectureDormiStdntMapper.deleteByPk */
	delete from t_lecture_dormi_stdnt 
	where DORMI_SEQ = #{dormiSeq} 
	and user_id = #{userId} and start_dt = #{startDt}

/* com.educare.edu.comn.mapper.LectureDormiStdntMapper.deleteByParam */
	delete from t_lecture_dormi_stdnt 
	where edu_seq = #{eduSeq} 
	 and user_id = #{userId}

mapper.select:
/* com.educare.edu.comn.mapper.LectureDormiStdntMapper.selectByParam */
	/** 학생 숙소 조회 */
	SELECT * FROM t_lecture_dormi_stdnt
	WHERE 1=1 
	and DORMI_SEQ = #{dormiSeq} 
	and user_id = #{userId}
